    Pocket.nc_XA = posRel.x;
    Pocket.nc_YA = partSelf._dimy - posRel.y;
    Pocket.nc_Side = "Btm";
    Pocket.nc_MprRelevant = partSelf.pa_ProgramQuery.Custom_ProductGroup == 'Wood' ? true : false;
