    Pocket.nc_BR = DU;
    Pocket.nc_KO = "00";
    Pocket.nc_LA = DU;
    Pocket.nc_RD = DU / 2;
    Pocket.nc_TI = part2.pa_DrillDepth;

  }

let DU = part2.pa_ProcessingTableData != undefined ? part2.pa_ProcessingTableData.DU : part2.pa_Diameter;

  if (DU == 2.5 || DU == 3 || DU == 4 || DU == 5 || DU == 6 || DU == 8 || DU == 8 || DU == 10 || DU == 15 || DU == 35) {

    let Drill = this.addncout_DrillVert();

    // StandardValue
    Drill.nc_TOOL="102";
    Drill.nc_XA=posRel.x;
    Drill.nc_YA=partSelf._dimy - posRel.y;
    Drill.nc_AN = 1;
    Drill.nc_Side = "Top";
    Drill.nc_MprRelevant = partSelf.pa_ProgramQuery.Custom_ProductGroup == 'Wood' || partSelf.pa_ProgramQuery.Custom_ProductGroup == 'Glass' && part2.pa_DrillDepth+2<partSelf._thickness ||  partSelf.pa_ProgramQuery.Custom_ProductGroup == 'Ceramics' && part2.pa_DrillDepth+1<partSelf._thickness ? true : false;
    Drill.nc_DrawingRelevant = true;

    // TableValues
    if(part2.pa_ProcessingTableData != undefined){
    Drill.nc_TI=part2.pa_ProcessingTableData.TI;
    Drill.nc_DU=part2.pa_ProcessingTableData.DU;
    Drill.nc_BM = part2.pa_ProcessingTableData.matrix_BM;
    Drill.nc_WI = part2.pa_ProcessingTableData.matrix_WI;
    Drill.nc_AB = part2.pa_ProcessingTableData.matrix_AB;
    Drill.nc_LA = part2.pa_ProcessingTableData.matrix_LA;
    Drill.nc_MI = part2.pa_ProcessingTableData.matrix_MI;
    Drill.nc_KO = part2.pa_ProcessingTableData.matrix_KO;
    }
    // AttributeValues
    else{
    Drill.nc_TI=part2.pa_DrillDepth;
    Drill.nc_DU=part2.pa_Diameter;
    Drill.nc_BM = part2.pa_DrillDepth >= partSelf._dimz && part2.pa_Diameter == 5 || part2.pa_Diameter == 6 || part2.pa_Diameter == 10 ? "LSL" : "LS"; 
    Drill.nc_WI = 0;
    Drill.nc_AB = 1;
    Drill.nc_LA = 0;
    Drill.nc_MI = 0;
    Drill.nc_KO = "00";
    }
  }
  else {
    let Pocket = this.addncout_Pocket();

    //StandardValue

    Pocket.nc_TOOL = "112";
    Pocket.nc_XA = posRel.x;
    Pocket.nc_YA = partSelf._dimy - posRel.y;
    Pocket.nc_Side = "Top";
    Pocket.nc_MprRelevant = partSelf.pa_ProgramQuery.Custom_ProductGroup == 'Wood' || partSelf.pa_ProgramQuery.Custom_ProductGroup == 'Glass' && part2.pa_DrillDepth+2<partSelf._thickness ||  partSelf.pa_ProgramQuery.Custom_ProductGroup == 'Ceramics' && part2.pa_DrillDepth+1<partSelf._thickness ? true : false;
    Pocket.nc_DrawingRelevant = true;

    Pocket.nc_BR = DU;
    Pocket.nc_KO = "00";
    Pocket.nc_LA = DU;
    Pocket.nc_RD = DU / 2;
    Pocket.nc_TI = part2.pa_DrillDepth;
  }

// Orientation of the drilling line and Handle length
  let Orientation = part2.pa_HandleOrientation == 'Vert' ? 90 : 0;
  let HandleLength = (part2.pa_DrillQty - 1) * part2.pa_DrillingDistance;

  // Calculate the position
  let PosX = part2.pa_HandleOrientation == 'Vert' ? posRel.x : posRel.x - HandleLength / 2;
  let PosY = part2.pa_HandleOrientation == 'Vert' ? partSelf._dimy - posRel.y - HandleLength / 2 : partSelf._dimy - posRel.y;

  // Add Vertical Drill
  for (let i = 1; i <= part2.pa_DrillQty; i++) {
    let DrillVert = this.addncout_DrillVert();
    DrillVert.nc_TOOL = "102";
    DrillVert.nc_XA = PosX;
    DrillVert.nc_YA = PosY;
    DrillVert.nc_TI = part2.pa_DrillDepth;
    DrillVert.nc_DU = part2.pa_Diameter;
    DrillVert.nc_BM = "LS"
    DrillVert.nc_WI = Orientation;
    DrillVert.nc_AB = 1;
    //DrillVert.nc_LA =  0;
    DrillVert.nc_MI = 0;
    DrillVert.nc_KO = "00";
    DrillVert.nc_AN = 1;
    DrillVert.nc_Side = part2.pa_DrillDepth >= partSelf._dimz ? "Btm" : "Top";

    DrillVert.nc_MprRelevant = partSelf.pa_ProgramQuery.Custom_ProductGroup == 'Wood' ? true : false;
    DrillVert.nc_DrawingRelevant = true

    PosY = part2.pa_HandleOrientation == 'Vert' ? PosY + part2.pa_DrillingDistance : PosY;
    PosX = part2.pa_HandleOrientation == 'Vert' ? PosX : PosX + part2.pa_DrillingDistance;
  }
